#!/usr/bin/env node

const fs = require('node:fs');
const path = require('node:path');
const { listFilesRecursive } = require('./tanstack-file-utils.js');

const ROOT_DIR = path.resolve(__dirname, '..');
const DEFAULT_LEGACY_API_DIR = path.join(
  ROOT_DIR,
  'apps',
  'web',
  'src',
  'legacy-api-routes'
);
const DEFAULT_APP_API_DIR = path.join(
  ROOT_DIR,
  'apps',
  'web',
  'src',
  'app',
  'api'
);
const GENERATED_MARKER =
  '// @generated by scripts/generate-web-api-route-wrappers.js. Do not edit manually.';
const HTTP_METHODS = [
  'GET',
  'HEAD',
  'POST',
  'PUT',
  'PATCH',
  'DELETE',
  'OPTIONS',
];

function toPosix(filePath) {
  return filePath.split(path.sep).join('/');
}

function routeFiles(directory, fsImpl = fs) {
  return listFilesRecursive(directory, fsImpl).filter(
    (filePath) => path.basename(filePath) === 'route.ts'
  );
}

function extractRouteMethods(source) {
  return HTTP_METHODS.filter((method) => {
    const functionExport = new RegExp(
      `\\bexport\\s+(?:async\\s+)?function\\s+${method}\\b`,
      'u'
    );
    const constExport = new RegExp(`\\bexport\\s+const\\s+${method}\\b`, 'u');
    const namedExport = new RegExp(
      `\\bexport\\s*\\{[^}]*\\b(?:as\\s+)?${method}\\b[^}]*\\}`,
      'u'
    );
    const destructuredConstExport = new RegExp(
      `\\bexport\\s+const\\s*\\{[^}]*\\b${method}\\b[^}]*\\}\\s*=`,
      'u'
    );

    return (
      functionExport.test(source) ||
      constExport.test(source) ||
      namedExport.test(source) ||
      destructuredConstExport.test(source)
    );
  });
}

function isGeneratedWrapper(source) {
  return source.startsWith(GENERATED_MARKER);
}

function legacyImportPath(relativeRouteFile) {
  return `@/legacy-api-routes/${toPosix(relativeRouteFile).replace(
    /\/route\.ts$/u,
    '/route'
  )}`;
}

function wrapperContent(relativeRouteFile, methods) {
  const hasGet = methods.includes('GET');
  const hasHead = methods.includes('HEAD');
  const needsHeadFallback = hasGet && !hasHead;
  const legacyModulePath = legacyImportPath(relativeRouteFile);
  const routeImports = [
    needsHeadFallback
      ? {
          line: "import { createLegacyHeadHandler } from '@/legacy-api-routes/head';",
          modulePath: '@/legacy-api-routes/head',
        }
      : null,
    {
      line: `import * as legacyRoute from '${legacyModulePath}';`,
      modulePath: legacyModulePath,
    },
  ]
    .filter((routeImport) => routeImport !== null)
    .sort((left, right) => left.modulePath.localeCompare(right.modulePath))
    .map((routeImport) => routeImport.line);
  const importLines = [GENERATED_MARKER, '', ...routeImports, ''];
  const exportLines = [];

  for (const method of HTTP_METHODS) {
    if (method === 'HEAD' && needsHeadFallback) {
      exportLines.push(
        'export const HEAD = createLegacyHeadHandler(legacyRoute.GET);'
      );
      continue;
    }

    if (methods.includes(method)) {
      exportLines.push(`export const ${method} = legacyRoute.${method};`);
    }
  }

  return `${[...importLines, ...exportLines].join('\n')}\n`;
}

function expectedWrappers({
  appApiDir,
  appV1Dir,
  fsImpl = fs,
  legacyApiDir,
  legacyV1Dir,
} = {}) {
  const sourceDir = legacyApiDir ?? legacyV1Dir ?? DEFAULT_LEGACY_API_DIR;
  const targetDir = appApiDir ?? appV1Dir ?? DEFAULT_APP_API_DIR;

  return routeFiles(sourceDir, fsImpl).flatMap((legacyRoutePath) => {
    const relativeRouteFile = toPosix(
      path.relative(sourceDir, legacyRoutePath)
    );
    const source = fsImpl.readFileSync(legacyRoutePath, 'utf8');
    const methods = extractRouteMethods(source);

    if (methods.length === 0) return [];

    return {
      content: wrapperContent(relativeRouteFile, methods),
      methods,
      relativeRouteFile,
      targetPath: path.join(targetDir, relativeRouteFile),
    };
  });
}

function collectGeneratedWrappers(
  appApiDir = DEFAULT_APP_API_DIR,
  fsImpl = fs
) {
  return routeFiles(appApiDir, fsImpl).filter((routePath) => {
    try {
      return isGeneratedWrapper(fsImpl.readFileSync(routePath, 'utf8'));
    } catch {
      return false;
    }
  });
}

function pruneEmptyDirectories(startDir, stopDir, fsImpl = fs) {
  let current = startDir;

  while (current.startsWith(stopDir) && current !== stopDir) {
    try {
      if (fsImpl.readdirSync(current).length > 0) return;
      fsImpl.rmdirSync(current);
      current = path.dirname(current);
    } catch {
      return;
    }
  }
}

function planWrapperChanges(options = {}) {
  const fsImpl = options.fsImpl ?? fs;
  const appApiDir =
    options.appApiDir ?? options.appV1Dir ?? DEFAULT_APP_API_DIR;
  const wrappers = expectedWrappers(options);
  const expectedTargets = new Set(
    wrappers.map((wrapper) => wrapper.targetPath)
  );
  const changes = [];

  for (const wrapper of wrappers) {
    const exists = fsImpl.existsSync(wrapper.targetPath);
    const current = exists
      ? fsImpl.readFileSync(wrapper.targetPath, 'utf8')
      : '';

    if (exists && !isGeneratedWrapper(current)) {
      changes.push({
        path: wrapper.targetPath,
        reason: 'non-generated target collision',
        type: 'collision',
      });
      continue;
    }

    if (current !== wrapper.content) {
      changes.push({
        content: wrapper.content,
        path: wrapper.targetPath,
        type: exists ? 'update' : 'create',
      });
    }
  }

  for (const generatedPath of collectGeneratedWrappers(appApiDir, fsImpl)) {
    if (!expectedTargets.has(generatedPath)) {
      changes.push({ path: generatedPath, type: 'delete' });
    }
  }

  return changes.sort((left, right) => left.path.localeCompare(right.path));
}

function applyWrapperChanges(changes, options = {}) {
  const fsImpl = options.fsImpl ?? fs;
  const appApiDir =
    options.appApiDir ?? options.appV1Dir ?? DEFAULT_APP_API_DIR;

  for (const change of changes) {
    if (change.type === 'collision') continue;

    if (change.type === 'delete') {
      fsImpl.unlinkSync(change.path);
      pruneEmptyDirectories(path.dirname(change.path), appApiDir, fsImpl);
      continue;
    }

    fsImpl.mkdirSync(path.dirname(change.path), { recursive: true });
    fsImpl.writeFileSync(change.path, change.content);
  }
}

function formatChanges(changes, rootDir = ROOT_DIR) {
  return changes
    .map((change) => {
      const relative = toPosix(path.relative(rootDir, change.path));
      return `${change.type}: ${relative}${change.reason ? ` (${change.reason})` : ''}`;
    })
    .join('\n');
}

function parseArgs(argv) {
  return {
    check: argv.includes('--check'),
    write: argv.includes('--write'),
  };
}

function main(argv = process.argv.slice(2)) {
  const args = parseArgs(argv);
  const changes = planWrapperChanges();
  const collisions = changes.filter((change) => change.type === 'collision');

  if (!args.check && !args.write) {
    throw new Error('Specify --check or --write.');
  }

  if (args.write) {
    if (collisions.length > 0) {
      console.error(formatChanges(collisions));
      return 1;
    }

    applyWrapperChanges(changes);
    console.log(
      changes.length === 0
        ? 'Legacy API route wrappers are current.'
        : `Updated ${changes.length} legacy API route wrapper file(s).`
    );
    return 0;
  }

  if (changes.length > 0) {
    console.error(
      `Legacy API route wrappers are stale:\n${formatChanges(changes)}`
    );
    return 1;
  }

  console.log('Legacy API route wrappers are current.');
  return 0;
}

if (require.main === module) {
  try {
    process.exitCode = main();
  } catch (error) {
    console.error(error instanceof Error ? error.message : String(error));
    process.exitCode = 1;
  }
}

module.exports = {
  GENERATED_MARKER,
  applyWrapperChanges,
  collectGeneratedWrappers,
  expectedWrappers,
  extractRouteMethods,
  isGeneratedWrapper,
  legacyImportPath,
  main,
  parseArgs,
  planWrapperChanges,
  wrapperContent,
};
